const Q_CHEMISTRY_2001=[{"id": "objective>Chemistry>2001>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer this questions.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If the gas is cooled, at what temperature will it start to condense?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">125<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">150<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">175<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">250<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the gas is cooled, the temperature will start to condense at 150<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C . </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2001>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the graph below to answer this questions.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> How long does it take all the solid to melt?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5mins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0mins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0mins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0mins</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the graph, It will take 2.5mins for all the solid to melt.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2001>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas X contains Z molecules at 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C  and  75mmHg.  How  many molecules will 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of another gas Y contain at the same temperature and pressure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2Y </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2Z </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Avogadro's law, equal volumes of all gases, at the same temperature and pressure, have the same number of molecules. Therefore, 25cm^3 of another gas Y will contain the same number of molecules, Z.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2001>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What mass of water is produced when 8.0g of hydrogen reacts with excess oxygen?  <br/>  [H = 1, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">36.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">72.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.0g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  2 moles of Hydrogen = 2 moles of water  <br/>  4g of Hydrogen gives 36 g of water  <br/>  So 8g of Hydrogen = (36 × 8)/4g of water = 72g of water.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2001>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle that contains 9 protons,10 neutrons and 10 electrons is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negative ion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral atom of a non metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral atom of a metal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a negative ion since there are more electrons than protons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2001>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cancerous growth are cured by exposure to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">γ -rays\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">β -rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">α -rays\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infrared rays</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cancerous growths are cured by exposure to gamma rays. Gamma rays are a form of electromagnetic radiation, like x-rays. These high-energy photons are much more penetrating than alpha or beta particles, but leave less ionization along their path.</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2001>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An oxide XO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> has a vapour density of 32. What is the atomic mass of X  <br/>  [O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">32\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">RMM = 2 x Vapour Density <br/> = 2 x 32 <br/> =64 <br/> Value of X <br/> Let the RAM of X be z <br/> RMM of XO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = (1 x RAM of X) + (2 x RAM of O) <br/> But  RMM = 64 <br/> Therefore; <br/> 64 = (1 x z) + (2 x 16) <br/> 64 = z + 32 <br/> z = 64 - 32 <br/> z = 32</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2001>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Millikan's contribution to the development of atomic theory is the determination of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">charge on electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charge to mass ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cathode rays</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Robert Millikan's oil drop experiment measured the charge of the electron. The experiment involved observing tiny charged droplets of oil located between two horizontal metal electrodes. Hence, Millikan's contribution to the development of atomic theory is the determination of charge on electron.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2001>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Four elements W, X, Y, and Z have atomic numbers 2, 6, 16 and 20 respectively. Which of these elements is a metal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X </div>", "<div style=\"font-family:Cambria;font-size:17px;\">W </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The element with atomic number 20 is Calcium, which is a metal. The atomic number is the number of protons in an atom, and it determines the chemical properties of an element and its place in the periodic table.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2001>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element X with relative atomic mass 16.2 contains two isotopes <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>X with relative abundance of 90% and <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">m</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>X with relative abundance of 10%. The value of m is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">RAM of X = (M1P1) + (M2P2) <br/> Where M1 = mass number of isotope 1 <br/> P1 = Percentage abundance of isotope 1 <br/> M2 = mass number of isotope 2 <br/> P2 = Percentage abundance of isotope 2 <br/> But RAM of X = 16.2 <br/> Therefore <br/> 16.2 = (90/100) x 16 + (10/100) x m <br/> 16.2 = (90 x 16) + (10m)/100 <br/> Clear the fraction <br/> 16.2 x 100 = 1440/10m <br/> 1620 = 1440 + 10m <br/> Collect like terms <br/> 1620-1440=10m <br/> 180=10m <br/> m = 18 <br/> </div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2001>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above represents the formation of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a metallic bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an electrovalent bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a covalent bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a coordinate bond</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is an illustration of the formation of a single covalent bond. This involves the sharing of an electron pair i.e a pair of electron between the participating atoms.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2001>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is correct about the average kinetic energy of the molecules of a gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It increases with increase in pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It increases at constant pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It increases with increase in temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It increase with increase in volume</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average kinetic energy of the molecules of a gas is directly proportional to the absolute temperature. Therefore, it increases with an increase in temperature.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2001>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pollutant from petroleum spillage in rivers and lakes can best be dispersed by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pouring detergents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">passing of ships through the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pouring organic solvents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pollutant from petroleum spillage in rivers and lakes can best be dispersed by pouring detergents. Detergents contain surfactants that reduce the surface tension of water, making it easier for oil to be broken up and dispersed.</div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>2001>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Deliquescent substances are used for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cooling  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wetting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drying</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deliquescent compounds absorb so much moisture from the air that they dissolve or turns into solution. Examples are calcium chloride and sodium hydroxide. They can be used for drying gases in the laboratory.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2001>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the curves below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If 1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of saturated solution of L at 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C is cooled to 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C, what amount in mole will separate out?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.75\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solubilities at 60°C and 25°C are 1.50 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> and 0.75 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> respectively  <br/>  When it cools from 60°C to 25°C, 1.5 - 0.75 mole of L = 0.75 mole will separate out.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2001>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the curves below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> At what temperature are the solubility of L and K the same?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">82<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is 82<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C because both curves intersect at this temperature.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2001>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pure solvents are obtained by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distillation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extraction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pure solvents are obtained by distillation. Distillation is a process of separating the component substances from a liquid mixture by selective evaporation and condensation.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2001>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the decrease in volume of air when pyrogallol is shaken with 30.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.63cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.06cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pyrogallol is used to dry Oxygen gas. Also recall that Oxygen is about 21% of air, so the 21% of 30.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> will be 6.3 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2001>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Environmental pollution is worsened by the release from automobile exhausts of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water vapour     </div>", "<div style=\"font-family:Cambria;font-size:17px;\">steam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">smoke\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heavy metals</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Automobile exhausts release smoke which contains harmful pollutants like carbon monoxide, nitrogen oxides, and particulate matter. These pollutants contribute to environmental pollution.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2001>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chemical used for coagulation in water purification is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aluminium tetraoxosulphate(VI) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper tetraoxosulphate(VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium tetraoxosulphate(VI) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium tetraoxosulphate(VI)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium tetraoxosulphate(VI), also known as aluminium sulphate, is commonly used in water treatment plants for coagulation. It helps to remove impurities and particles from water by causing them to clump together and settle at the bottom.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2001>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Phosphorus is stored under water to prevent it from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dehydrating\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">becoming inert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">smelling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">catching fire</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Phosphorus is a highly reactive non-metal that catches fire when exposed to air. To prevent this, it is stored under water.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : PHOSPHORUS"}, {"id": "objective>Chemistry>2001>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following reactions does reduction takes place</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> - e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> → O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cr - 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reduction is a chemical reaction that involves the gain of electrons. In the reaction 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 2e → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, hydrogen ions (H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) are gaining electrons to form hydrogen gas (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), hence reduction is taking place.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2001>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌ 3R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ∆H is negative. which of the following will increase the yield of R? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Using a larger closed vessel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">removing some S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding a positive catalyst</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's principle, if a dynamic equilibrium is disturbed by changing the conditions, the position of equilibrium moves to counteract the change. In this case, removing some S (a product) will shift the equilibrium to the right to increase the yield of R.</div>", "topic": "CHEMICAL EQUILIBRIA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2001>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal M displaces zinc from zinc chloride solution. This shows that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M is more electronegative than zinc </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc is above hydrogen in the series </div>", "<div style=\"font-family:Cambria;font-size:17px;\">M is more electropositive than zinc </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons flow from zinc to M</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a metal M displaces zinc from zinc chloride solution, it means that M is more reactive than zinc. In the reactivity series, a more reactive metal is more electropositive. Therefore, M is more electropositive than zinc.</div>", "topic": "METALS AND THEIR COMPOUNDS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2001>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best explains the increase in the rate of a chemical reaction as the temperature rises?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The bonds, in the reacting molecules are more readily broken</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The molecular collisions  becomes more violent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A lower proportion of the molecules has the necessary minimum energy to react</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The collision frequency of the molecules increases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a chemical reaction increases with temperature because the kinetic energy of the molecules increases. This leads to an increase in the frequency of collisions between molecules, thereby increasing the chances of a successful reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2001>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What current in amperes will  deposit 2.7g of aluminium in 2 hours?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">32\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Al  <br/> From the equation above <br/> 3 Faraday of electricity produced 2.7g of Aluminum X coulombs of electricity  <br/> But 1 Faraday = 96500C and 3 Faraday = 3 x 96500=289500C <br/> Therefore <br/> 289500C of electricity produced 27g of Al X coulombs of electricity will produce 2.7g of Al <br/> X = 289500 x 2.7/27 <br/> =781650/27 <br/> =28950C <br/> But quantity of electricity, Q =It <br/> I=Q/t <br/> But t = 2 hours= 120 minutes = 120 x 60 =7200 seconds <br/> I= 28950/7200 <br/> I = 4.02= 4 amperes</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2001>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanoic acid is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tribasic\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unionizeable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monobasic   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dibasic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanoic acid, also known as acetic acid, is a monobasic acid. This means it has one replaceable hydrogen atom in its molecule which can be donated as a proton to a base.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2001>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → CS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(g) → ∆ H = +89kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> The chemical equation above implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">each of carbon and sulphur has 89kJ of energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both carbon and sulphur contribute 89kJ of energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">89kJ energy is released</div>", "<div style=\"font-family:Cambria;font-size:17px;\">89kJ is absorbed</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The positive sign in front of the heat of reaction (∆ H = +89kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) indicates that the reaction is endothermic. This means that 89kJ of energy is absorbed from the surroundings for the reaction to occur.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2001>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> ∆H = -189kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  The equilibrium constant for the reaction above is increased by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreasing the temperature of the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the pressure of the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the  addition of a catalyst to the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the surface area of the vessel</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in temperature favours in Equilibrium Constant[k] for this exothermic reaction.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2001>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">3Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 9HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 3Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(i)</span> + 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/>  In the equation above, Copper is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an electron acceptor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reducing agent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, Copper (Cu) is being oxidized to Copper Nitrate (Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). This means it is losing electrons and therefore, it is a reducing agent.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2001>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When ∆H is negative, a reaction is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionic\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reversible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exothermic\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endothermic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ∆H (change in enthalpy) is negative, it means that the reaction is exothermic. An exothermic reaction is a chemical reaction that releases energy by light or heat.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2001>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As the concentration of an electrolyte reduces, the conductivity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduces to zero  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is unaffected</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conductivity of an electrolyte solution is directly proportional to the concentration of the electrolyte. Therefore, as the concentration of an electrolyte reduces, the conductivity of the solution also decreases.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2001>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following reaction has the oxidation number of nitrogen increased?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> → 2NOBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → Fe(NO)SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oxidation is the loss of electrons or an increase in oxidation state of a molecule, atom, or ion. This is due to the O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2001>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>(g) + HCl(g) → NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl(s). <br/>  The entropy change in the system above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negative\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indeterminate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entropy is a measure of the disorder or randomness of a system. In the given reaction, gaseous reactants are combining to form a solid product. This results in a decrease in disorder, hence the entropy change is negative.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2001>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fermentation is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">breaking down of carbohydrate to glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conversion of sugar to alcohol in the presence of yeast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">breaking down of sugar to carbohydrate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conversion of alcohol to sugar in the presence of yeast</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fermentation is a metabolic process that produces chemical changes in organic substrates through the action of enzymes. In fermentation, sugar is converted to alcohol in the presence of yeast.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2001>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula for the alkanals is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ROH\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO </div>", "<div style=\"font-family:Cambria;font-size:17px;\">RCOOR<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">I</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RCHO</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula for alkanals (also known as aldehydes) is RCHO, where R represents any alkyl group.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2001>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main impurity in iron ore during the extraction of iron is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silicon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium trioxosilicate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur(II) oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main impurity in iron ore during the extraction of iron is silicon(IV) oxide.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2001>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the vulcanization of rubber,sulphur is added to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">break down rubber polymer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lengthen the chain of rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bind rubber molecules together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">act as catalyst</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the vulcanization of rubber, sulphur is added to create cross-links between the rubber molecules, which helps to improve the rubber's elasticity and strength. Therefore, sulphur is added to bind rubber molecules together.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2001>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Catalytic hydrogenation of benzene produces</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclohexene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclohexane\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">margarine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Catalytic hydrogenation of benzene produces cyclohexane. This is because hydrogenation is a chemical reaction between molecular hydrogen (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) and another compound or element, usually in the presence of a catalyst. In this case, the benzene (a six carbon ring structure) reacts with hydrogen to form cyclohexane.</div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2001>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A trihydric alkanol is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glycerol\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phenol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glycol\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanols or Alcohols containing three hydroxyl (-OH) groups are known as trihydric alcohols. An example is glycerol. A trihydric alkanol is glycerol. Glycerol is a simple polyol compound. It is a colorless, odorless, viscous liquid that is sweet-tasting and non-toxic. The glycerol backbone is found in those lipids known as glycerides.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2001>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When chlorine is passed into water and the resulting solution exposed to sunlight, the product formed are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorine gas and hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen and oxochlorate(I) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine gas and oxochlorate(I) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrochloric acid and oxygen</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When chlorine is passed into water and the resulting solution exposed to sunlight, the products formed are hydrochloric acid and oxygen. This is because the sunlight provides the energy needed for the chlorine to react with the water.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2001>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Proteins in acid solution undergo</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">polymerization\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">substitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Proteins in acid solution undergo hydrolysis. Hydrolysis is a reaction involving the breaking of a bond in a molecule using water. The reaction mainly occurs between an ion and water molecules and often changes the pH of a solution.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2001>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic reaction of the compounds with the general formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">esterification\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymerization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decarboxylation  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">substitution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is polymerization. Polymerization is a process of reacting monomer molecules together in a chemical reaction to form polymer chains or three-dimensional networks.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2001>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pair of organic compounds that are isomers is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">benzene and methylbenzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trichloromethane and tetrachloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol and propanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">but–1– ene and but– 2–ene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pair of organic compounds that are isomers is but–1– ene and but– 2–ene. Isomers are molecules that have the same molecular formula, but have a different arrangement of the atoms in space.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2001>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A burning candle produces water and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon(II) oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A burning candle produces water and carbon(IV) oxide. This is because the wax in the candle, which is a hydrocarbon, reacts with oxygen in the air to produce water and carbon dioxide.</div>", "topic": "CHEMICAL COMBINATION : COMBUSTION REACTIONS"}, {"id": "objective>Chemistry>2001>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that can best be collected by downward displacement of air is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorine\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV) oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that can best be collected by downward displacement of air is ammonia. This is because ammonia is lighter than air and will rise, hence it can be collected by downward displacement of air.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2001>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals burns with a brick-red flame?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pb\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium (Ca) burns with a brick-red flame. This is a characteristic of calcium and is used in flame tests to identify the presence of calcium.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2001>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following represents hybridization in ethyne?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>d\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hybridization in ethyne is sp. Hybridization is the concept of mixing atomic orbitals into new hybrid orbitals suitable for the pairing of electrons to form chemical bonds in valence bond theory. In ethyne, each carbon atom is sp hybridized.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2001>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">22</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(q)</span> → 12C(s) + 11H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O(I) + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span>   <br/>  In the reaction above, tetraoxosulphate (VI) acid functions as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a dehydrating agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reducing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a catalyst</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, tetraoxosulphate (VI) acid (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) removes water from sucrose (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">22</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>), leaving behind carbon. This process is known as dehydration, hence H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> acts as a dehydrating agent.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2001>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium react with water, the resulting solution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weakly acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkaline</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium reacts with water, it forms sodium hydroxide and hydrogen gas. Sodium hydroxide is a strong base, hence the resulting solution is alkaline.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}];
